1	<!DOCTYPE html>
2	<html lang="zh-CN">
3	<head>
4	    <meta charset="UTF-8">
5	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
6	    <title><%= title %> | 我的技术博客</title>
7	    <link rel="icon" type="image/x-icon" href="./assets/img/favicons/favicon.ico">
8	    <link rel="icon" type="image/png" sizes="32x32" href="./assets/img/favicons/favicon-32x32.png">
9	    <link rel="icon" type="image/png" sizes="16x16" href="./assets/img/favicons/favicon-16x16.png">
10	    <link rel="apple-touch-icon" sizes="180x180" href="./assets/img/favicons/apple-touch-icon.png">
11	    <link rel="stylesheet" href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600&family=Source+Serif+Pro:ital,wght@0,400;0,700;1,400&display=swap">
12	    <link rel="stylesheet" href="style.css">
13	    <!-- highlight.js 主题由 style.css 统一管理，不再引入外部主题 -->
14	</head>
15	<body>
16	    <nav class="navbar">
17	        <div class="container">
18	            <a href="index.html" class="logo">Blog.</a>
19	            <ul class="nav-links">
20	                <li><a href="index.html">返回首页</a></li>
21	            </ul>
22	        </div>
23	    </nav>
24	
25	    <main class="container">
26	        <article class="post">
27	            <header class="post-header">
28	                <time><%= date %></time>
29	                <h1><%= title %></h1>
30	                <% if (subtitle) { %>
31	                    <p class="subtitle"><%= subtitle %></p>
32	                <% } %>
33	                <div class="post-meta">
34	                    <% if (categories && categories.length) { %>
35	                        <span class="post-categories"><%= categories.join(' / ') %></span>
36	                    <% } %>
37	                    <% if (tags && tags.length) { %>
38	                        <span class="post-tags">
39	                            <% tags.forEach(function(tag, i) { %>
40	                                <a href="#" class="post-header-tag" data-tag="<%= tag %>"><%= tag %></a>
41	                            <% }) %>
42	                        </span>
43	                    <% } %>
44	                </div>
45	            </header>
46	
47	            <section class="post-content">
48	                <%- content %>
49	            </section>
50	        </article>
51	    </main>
52	
53	    <footer class="container">
54	        <p>&copy; 2026 saveole.</p>
55	    </footer>
56	
57	    <div class="tag-popup-overlay" id="tagPopupOverlay"></div>
58	    <div class="tag-popup" id="tagPopup">
59	        <div class="tag-popup-header">
60	            <h3><span class="tag-popup-tag-name" id="tagPopupName"></span></h3>
61	            <button class="tag-popup-close" id="tagPopupClose">&times;</button>
62	        </div>
63	        <ul class="tag-popup-list" id="tagPopupList"></ul>
64	    </div>
65	
66	    <script>
67	    (function() {
68	        var tagIndex = <%- tagIndex %>;
69	        var popup = document.getElementById('tagPopup');
70	        var overlay = document.getElementById('tagPopupOverlay');
71	        var popupName = document.getElementById('tagPopupName');
72	        var popupList = document.getElementById('tagPopupList');
73	        var popupClose = document.getElementById('tagPopupClose');
74	
75	        function closePopup() {
76	            popup.classList.remove('active');
77	            overlay.classList.remove('active');
78	        }
79	
80	        function openPopup(tag) {
81	            var posts = tagIndex[tag] || [];
82	            popupName.textContent = '#' + tag;
83	            popupList.innerHTML = '';
84	            if (posts.length === 0) {
85	                popupList.innerHTML = '<li class="tag-popup-empty">暂无相关文章</li>';
86	            } else {
87	                posts.sort(function(a, b) { return a.date > b.date ? -1 : 1; });
88	                posts.forEach(function(p) {
89	                    var li = document.createElement('li');
90	                    var a = document.createElement('a');
91	                    a.href = p.url;
92	                    a.innerHTML = '<span class="popup-post-title">' + p.title + '</span><span class="popup-post-date">' + p.date + '</span>';
93	                    li.appendChild(a);
94	                    popupList.appendChild(li);
95	                });
96	            }
97	            popup.classList.add('active');
98	            overlay.classList.add('active');
99	        }
100	
101	        overlay.addEventListener('click', closePopup);
102	        popupClose.addEventListener('click', closePopup);
103	        document.addEventListener('keydown', function(e) {
104	            if (e.key === 'Escape') closePopup();
105	        });
106	
107	        document.addEventListener('click', function(e) {
108	            var el = e.target.closest('.inline-tag, .post-header-tag');
109	            if (el) {
110	                e.preventDefault();
111	                openPopup(el.getAttribute('data-tag'));
112	            }
113	        });
114	    })();
115	    </script>
116	</body>
117	</html>

1	:root {
2	  --bg-color: #f8f9fa;
