9	  --content-width: 720px;
10	  --run-0: #ebedf0;
11	  --run-1: #86efac;
12	  --run-2: #fde047;
13	  --run-3: #fb923c;
14	  --run-4: #ef4444;
15	  --run-5: #b91c1c;
16	  --token-0: #ebedf0;
17	  --token-1: #c6e0ff;
18	  --token-2: #7db8ff;
19	  --token-3: #3b8aff;
20	  --token-4: #2563eb;
21	  --empty-cell: #ebedf0;
22	}
23	
24	/* 基础重置 */
25	* {
26	  box-sizing: border-box;
27	  margin: 0;
28	  padding: 0;
29	}
30	
31	body {
32	  background-color: var(--bg-color);
33	  color: var(--text-main);
34	  font-family: "Source Serif Pro", serif;
35	  line-height: 1.8;
36	}
37	
38	/* 居中核心：container */
39	.container {
40	  max-width: var(--content-width);
41	  margin: 0 auto; /* 水平居中 */
42	  padding: 0 1.5rem;
43	}
44	
45	/* 导航和页脚居中 */
46	.navbar,
47	footer {
48	  width: 100%;
49	  padding: 2rem 0;
50	}
51	
52	.navbar-inner {
53	  display: flex;
54	  justify-content: space-between;
55	  align-items: center;
56	}
57	
58	.nav-link {
59	  font-family: "Inter", sans-serif;
60	  font-size: 0.82rem;
61	  color: var(--text-muted);
62	  text-decoration: none;
63	  letter-spacing: 0.2px;
64	  position: relative;
65	  padding-bottom: 2px;
66	  transition: color 0.25s ease;
67	}
68	
69	.nav-link::after {
70	  content: "";
71	  position: absolute;
72	  bottom: 0;
73	  left: 0;
74	  width: 0;
75	  height: 1px;
76	  background: var(--primary-color);
77	  transition: width 0.3s ease;
78	}
79	
80	.nav-link:hover {
81	  color: var(--text-main);
82	}
83	
84	.nav-link:hover::after {
85	  width: 100%;
86	}
87	
88	.post {
89	  margin-top: 4rem;
90	}
91	
92	/* Post header meta (categories + tags) */
93	.post-meta {
94	  display: flex;
95	  align-items: center;
96	  gap: 0.75rem;
97	  margin-top: 0.6rem;
98	  flex-wrap: wrap;
99	}
100	
101	.post-categories {
102	  font-family: "Inter", sans-serif;
103	  font-size: 0.78rem;
104	  color: var(--text-muted);
105	}
106	
107	.post-tags {
108	  display: flex;
109	  flex-wrap: wrap;
110	  gap: 0.35rem;
111	}
112	
113	.post-header-tag {
114	  font-family: "Inter", sans-serif;
115	  font-size: 0.75rem;
116	  font-weight: 500;
117	  color: var(--primary-color);
118	  background: color-mix(in srgb, var(--primary-color) 8%, transparent);
119	  border: 1px solid color-mix(in srgb, var(--primary-color) 15%, transparent);
120	  padding: 1px 8px;
121	  border-radius: 4px;
122	  text-decoration: none;
123	  cursor: pointer;
124	  transition: background 0.2s;
125	}
126	
127	.post-header-tag:hover {
128	  background: color-mix(in srgb, var(--primary-color) 16%, transparent);
129	}
130	
131	.post-content p {
132	  margin-bottom: 1.5rem;
133	}
134	
135	/* ====== 代码块样式 - 与博客主题统一 ====== */
136	
137	/* 行内代码 */
138	code {
139	  background: var(--code-bg);
140	  color: var(--code-color);
141	  padding: 0.2em 0.4em;
142	  border-radius: 4px;
143	  font-family: "JetBrains Mono", "Courier New", monospace;
144	  font-size: 0.88em;
145	}
146	
147	/* 代码块容器 */
148	pre {
149	  background: var(--code-bg);
150	  color: var(--code-color);
151	  padding: 1.5rem;
152	  border-radius: 8px;
153	  overflow-x: auto;
154	  margin: 2rem 0;
155	  font-family: "JetBrains Mono", "Courier New", monospace;
156	  font-size: 0.9rem;
157	  line-height: 1.5;
158	  border: 1px solid var(--border-color);
159	}
160	
161	/* pre 内的 code 不重复加背景和 padding */
162	pre code {
163	  background: transparent;
164	  color: inherit;
165	  padding: 0;
166	  border-radius: 0;
167	  font-size: inherit;
168	}
169	
170	/* ====== Highlight.js 北欧风配色 (浅色主题) ====== */
171	.hljs {
172	  color: var(--text-main);
173	}
174	
175	.hljs-keyword,
176	.hljs-selector-tag,
177	.hljs-literal {
178	  color: #2563eb;
179	  font-weight: bold;
180	}
181	
182	.hljs-string,
183	.hljs-addition,
184	.hljs-regexp,
185	.hljs-attr {
186	  color: #059669;
187	}
188	
189	.hljs-comment,
190	.hljs-quote,
191	.hljs-meta .hljs-meta-string,
192	.hljs-doctag {
193	  color: #94a3b8;
194	  font-style: italic;
195	}
196	
197	.hljs-number,
198	.hljs-built_in,
199	.hljs-type,
200	.hljs-template-variable,
201	.hljs-tag .hljs-attr {
202	  color: #d97706;
203	}
204	
205	.hljs-title,
206	.hljs-function,
207	.hljs-title.class_,
208	.hljs-section {
209	  color: #7c3aed;
210	}
211	
212	.hljs-attr,
213	.hljs-attribute,
214	.hljs-variable {
215	  color: #9333ea;
216	}
217	
218	.hljs-symbol,
219	.hljs-bullet,
220	.hljs-link,
221	.hljs-subst {
222	  color: #0891b2;
223	}
224	
225	.hljs-deletion {
226	  color: #dc2626;
227	  background: rgba(220, 38, 38, 0.08);
228	}
229	
230	.hljs-meta {
231	  color: #64748b;
232	}
233	
234	.hljs-emphasis {
235	  font-style: italic;
236	}
237	.hljs-strong {
238	  font-weight: bold;
239	}
240	
241	/* ====== 暗色模式代码块 ====== */
242	@media (prefers-color-scheme: dark) {
243	  :root {
244	    --bg-color: #0f172a;
245	    --text-main: #e2e8f0;
246	    --text-muted: #94a3b8;
247	    --primary-color: #60a5fa;
248	    --border-color: #1e293b;
249	    --code-bg: #1e293b;
250	    --code-color: #e2e8f0;
251	    --run-0: #161b22;
252	    --run-1: #16a34a;
253	    --run-2: #ca8a04;
254	    --run-3: #ea580c;
255	    --run-4: #dc2626;
256	    --run-5: #7f1d1d;
257	    --token-0: #161b22;
258	    --token-1: #1d4ed8;
259	    --token-2: #2563eb;
260	    --token-3: #3b82f6;
261	    --token-4: #60a5fa;
262	    --empty-cell: #161b22;
263	  }
264	
265	  pre {
266	    border-color: #334155;
267	  }
268	
269	  .hljs {
270	    color: #e2e8f0;
271	  }
272	
273	  .hljs-keyword,
274	  .hljs-selector-tag,
275	  .hljs-literal {
276	    color: #93c5fd;
277	  }
278	
279	  .hljs-string,
280	  .hljs-addition,
281	  .hljs-regexp,
282	  .hljs-attr {
283	    color: #6ee7b7;
284	  }
285	
286	  .hljs-comment,
287	  .hljs-quote {
288	    color: #64748b;
289	  }
290	
291	  .hljs-number,
292	  .hljs-built_in,
293	  .hljs-type,
294	  .hljs-template-variable {
295	    color: #fcd34d;
296	  }
297	
298	  .hljs-title,
299	  .hljs-function,
300	  .hljs-title.class_,
301	  .hljs-section {
302	    color: #c4b5fd;
303	  }
304	
305	  .hljs-attr,
306	  .hljs-attribute,
307	  .hljs-variable {
308	    color: #f0abfc;
309	  }
310	
311	  .hljs-symbol,
312	  .hljs-bullet,
313	  .hljs-link,
314	  .hljs-subst {
315	    color: #67e8f9;
316	  }
317	
318	  .hljs-deletion {
319	    color: #fca5a5;
320	    background: rgba(239, 68, 68, 0.15);
321	  }
322	
323	  .contrib-cell[data-tooltip]:hover::after {
324	    background: rgba(30, 41, 59, 0.75);
325	    border-color: #334155;
326	  }
327	}
