142	<script>
143	// 统一的全局时间轴
144	const timeline = [
145	    "2025-11-03", "2025-11-14", "2025-11-18", "2025-11-20", "2025-12-03", 
146	    "2025-12-10", "2025-12-23", "2026-01-05", "2026-01-06", "2026-01-07", 
