149	    "2026-05-12", "2026-05-13", "2026-05-19", "2026-05-20"
150	];
151	
152	// 图表所需的数据空槽位
153	const weightData = Array(timeline.length).fill(null);
154	const fatData = Array(timeline.length).fill(null);
155	const distanceData = Array(timeline.length).fill(null);
156	const hrData = Array(timeline.length).fill(null);
157	
158	// 模拟未来的真实全量跑步列表数据数据（此处包含具体的时间点与活动名称）
159	const rawRunningList = [
