89	    <script>
90	    (function() {
91	        var data = <%- dailyData %>;
92	        if (!data || !data.days || data.days.length === 0) return;
93	
94	        var tokenMap = {};
95	        var runningMap = {};
96	        data.days.forEach(function(d) {
97	            if (d.total_tokens) {
98	                var t = d.total_tokens;
99	                tokenMap[d.date] = t.input + t.output + t.cache_read + t.cache_creation;
100	            }
101	            if (d.running_km) runningMap[d.date] = d.running_km;
102	        });
103	
104	        var today = new Date();
105	        var todayStr = today.getFullYear() + '-' +
106	            String(today.getMonth() + 1).padStart(2, '0') + '-' +
107	            String(today.getDate()).padStart(2, '0');
108	
109	        var oneYearAgo = new Date(today);
110	        oneYearAgo.setFullYear(oneYearAgo.getFullYear() - 1);
111	        var dayOfWeek = oneYearAgo.getDay();
112	        var mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
113	        var startDate = new Date(oneYearAgo);
114	        startDate.setDate(startDate.getDate() + mondayOffset);
115	
116	        var weeks = [];
117	        var monthLabels = [];
118	        var lastMonth = -1;
119	
120	        function toDateStr(d) {
121	            return d.getFullYear() + '-' +
122	                String(d.getMonth() + 1).padStart(2, '0') + '-' +
123	                String(d.getDate()).padStart(2, '0');
124	        }
125	
126	        while (toDateStr(startDate) <= todayStr) {
127	            var week = [];
128	            for (var i = 0; i < 7; i++) {
129	                var dateStr = toDateStr(startDate);
130	                var month = startDate.getMonth();
131	                if (i === 0 && month !== lastMonth) {
132	                    monthLabels.push({
133	                        month: startDate.toLocaleString('zh-CN', { month: 'short' }),
134	                        weekIndex: weeks.length
135	                    });
136	                    lastMonth = month;
137	                }
138	                week.push({
139	                    date: dateStr,
140	                    tokens: tokenMap[dateStr] || 0,
141	                    running: runningMap[dateStr] || 0,
142	                    future: dateStr > todayStr
143	                });
144	                startDate.setDate(startDate.getDate() + 1);
145	            }
146	            weeks.push(week);
147	        }
148	
149	        // Token color levels (quartile-based, all data)
150	        var tokenValues = Object.values(tokenMap).filter(function(v) { return v > 0; }).sort(function(a, b) { return a - b; });
151	        function getQuantile(arr, q) {
152	            var pos = (arr.length - 1) * q;
153	            var base = Math.floor(pos);
154	            var rest = pos - base;
155	            if (arr[base + 1] !== undefined) return arr[base] + rest * (arr[base + 1] - arr[base]);
156	            return arr[base];
157	        }
158	        var q1 = tokenValues.length > 0 ? getQuantile(tokenValues, 0.25) : 0;
159	        var q2 = tokenValues.length > 0 ? getQuantile(tokenValues, 0.5) : 0;
160	        var q3 = tokenValues.length > 0 ? getQuantile(tokenValues, 0.75) : 0;
161	
162	        function getTokenLevel(v) {
163	            if (v === 0) return 0;
164	            if (v <= q1) return 1;
165	            if (v <= q2) return 2;
166	            if (v <= q3) return 3;
167	            return 4;
168	        }
169	
170	        function getRunLevel(km) {
171	            if (km <= 0) return 0;
172	            if (km < 3) return 1;
173	            if (km < 5) return 2;
174	            if (km < 10) return 3;
175	            if (km < 15) return 4;
176	            return 5;
177	        }
178	
179	        function formatRunning(km) {
180	            return km < 10 ? km.toFixed(1) : km.toFixed(0);
181	        }
182	
183	        function formatTokens(n) {
184	            if (n >= 1e6) return (n / 1e6).toFixed(1) + ' M';
185	            if (n >= 1e3) {
186	                var k = n / 1e3;
187	                return (k >= 100 ? k.toFixed(0) : k.toFixed(1)) + ' K';
188	            }
189	            return String(n);
190	        }
191	
192	        // Render month labels
193	        var monthsEl = document.getElementById('contrib-months');
194	        var monthHtml = '';
195	        var prevWeekIdx = -10;
196	        monthLabels.forEach(function(m) {
197	            var offset = m.weekIndex * 12;
198	            if (m.weekIndex > prevWeekIdx + 3) {
199	                monthHtml += '<span style="position:absolute;left:' + offset + 'px">' + m.month + '</span>';
200	                prevWeekIdx = m.weekIndex;
201	            }
202	        });
203	        monthsEl.innerHTML = monthHtml;
204	
205	        // Render grid
206	        var totalWeeks = weeks.length;
207	        var edgeCount = 8;
208	        var gridEl = document.getElementById('contrib-grid');
209	        var gridHtml = '';
210	
211	        weeks.forEach(function(week, wi) {
212	            week.forEach(function(day, di) {
213	                if (day.future) {
214	                    gridHtml += '<span class="contrib-cell" data-date="' + day.date + '" style="grid-column:' + (wi + 1) + ';grid-row:' + (di + 1) + '"></span>';
215	                    return;
216	                }
217	
218	                var hasRun = day.running > 0;
219	                var hasTok = day.tokens > 0;
220	                var runLvl = getRunLevel(day.running);
221	                var tokLvl = getTokenLevel(day.tokens);
222	
223	                var bg;
224	                if (hasRun && hasTok) {
225	                    bg = 'background:linear-gradient(90deg,var(--run-' + runLvl + ') 50%,var(--token-' + tokLvl + ') 50%)';
226	                } else if (hasRun) {
227	                    bg = 'background:var(--run-' + runLvl + ')';
228	                } else if (hasTok) {
229	                    bg = 'background:var(--token-' + tokLvl + ')';
230	                } else {
231	                    bg = 'background:var(--empty-cell)';
232	                }
233	
234	                var cls = 'contrib-cell';
235	                if (wi < edgeCount) cls += ' edge-left';
236	                if (wi >= totalWeeks - edgeCount) cls += ' edge-right';
237	
238	                var runStr = (hasRun ? formatRunning(day.running) : '0') + ' km';
239	                var tokStr = hasTok ? formatTokens(day.tokens) : '0 M';
240	                var tooltip = day.date + '\n🏃 ' + runStr + '\n💻 ' + tokStr;
241	
242	                gridHtml += '<span class="' + cls + '" data-date="' + day.date + '" data-tooltip="' + tooltip + '" style="' + bg + ';grid-column:' + (wi + 1) + ';grid-row:' + (di + 1) + '"></span>';
243	            });
244	        });
245	        gridEl.innerHTML = gridHtml;
246	
247	        // Summary statistics
248	        var totalTokens = 0, totalRunning = 0, activeDays = 0;
249	        weeks.forEach(function(week) {
250	            week.forEach(function(day) {
251	                if (day.future) return;
252	                if (day.tokens > 0) { totalTokens += day.tokens; }
253	                if (day.running > 0) { totalRunning += day.running; }
254	                if (day.tokens > 0 || day.running > 0) { activeDays++; }
255	            });
256	        });
257	        var summaryParts = [];
258	        if (totalTokens > 0) summaryParts.push(formatTokens(totalTokens) + ' tokens');
259	        if (totalRunning > 0) summaryParts.push(totalRunning.toFixed(0) + ' km');
260	        if (activeDays > 0) summaryParts.push(activeDays + ' 天活跃');
261	        var summaryEl = document.getElementById('contrib-summary');
262	        if (summaryEl && summaryParts.length > 0) {
263	            summaryEl.textContent = '· ' + summaryParts.join(' · ');
264	        }
265	
266	        // Info panel click toggle (touch-friendly)
267	        var infoBtn = document.querySelector('.legend-info-btn');
268	        var infoPanel = document.querySelector('.legend-info-panel');
269	        if (infoBtn && infoPanel) {
270	            infoBtn.addEventListener('click', function(e) {
271	                e.stopPropagation();
272	                infoPanel.classList.toggle('active');
273	            });
274	            document.addEventListener('click', function(e) {
275	                if (!infoPanel.contains(e.target) && e.target !== infoBtn) {
276	                    infoPanel.classList.remove('active');
277	                }
278	            });
279	        }
280	    })();
281	    </script>
282	</body>
283	</html>

