208	            x: { ...commonScalesX, ticks: { display: false } },
209	            yW: { type: 'linear', position: 'left', min: 70, max: 85, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 5, callback: v => v+' kg' }, grid: { color: '#f2eee9' }, border: { display: false } },
210	            yF: { type: 'linear', position: 'right', min: 15, max: 35, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 5, callback: v => v+' %' }, grid: { display: false }, border: { display: false } }
211	        }
212	    }
213	});
214	
215	const chartRunning = new Chart(document.getElementById('runningChart').getContext('2d'), {
216	    data: {
217	        labels: timeline,
218	        datasets: [
219	            { type: 'bar', label: '跑步距离', data: distanceData, backgroundColor: 'rgba(92, 118, 141, 0.4)', hoverBackgroundColor: 'rgba(92, 118, 141, 0.7)', barThickness: 6, yAxisID: 'yDistance' },
220	            { type: 'line', label: '平均心率', data: hrData, borderColor: '#db8a75', backgroundColor: 'transparent', borderWidth: 2, pointRadius: 1.5, spanGaps: true, tension: 0.4, yAxisID: 'yH' }
221	        ]
222	    },
223	    options: {
224	        responsive: true, maintainAspectRatio: false,
225	        plugins: { legend: { position: 'top', align: 'end', labels: { boxWidth: 6, usePointStyle: true, font: { size: 11 } } }, tooltip: { usePointStyle: true } },
226	        scales: {
227	            x: commonScalesX,
228	            yDistance: { type: 'linear', position: 'left', min: 0, max: 20, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 5, callback: v => v+' km' }, grid: { color: '#f2eee9' }, border: { display: false } },
229	            yH: { type: 'linear', position: 'right', min: 110, max: 160, ticks: { color: '#a0aab0', font: { size: 10 }, stepSize: 10, callback: v => v+' bpm' }, grid: { display: false }, border: { display: false } }
230	        }
231	    }
232	});
233	
234	// 多图表垂直十字联动
235	function triggerHover(targetChart, event) {
236	    const points = targetChart.getElementsAtEventForMode(event, 'index', { intersect: false }, true);
237	    if (points.length > 0) { targetChart.setActiveElements(points); targetChart.tooltip.setActiveElements(points, { x: event.x, y: event.y }); targetChart.update('none'); }
238	}
239	document.getElementById('bodyChart').addEventListener('mousemove', (e) => { triggerHover(chartRunning, Chart.helpers.getRelativePosition(e, chartBody)); });
240	document.getElementById('runningChart').addEventListener('mousemove', (e) => { triggerHover(chartBody, Chart.helpers.getRelativePosition(e, chartRunning)); });
241	</script>
242	</body>
